+        var it = dialogs.listIterator();
+        var prev = it.next();
+        do {
+            var next = it.next();
+            var pair = new DialogPair(prev, next);
+            pairs.add(pair);
+            pairs.add(pair.flip());
+            prev = next;
+        } while (it.hasNext());
+
+        return pairs;
+    }
