+static void print_fd_details(int fd, char* out, size_t outlen) {
+    const char* type = "unknown";
+    char link[1024] = { 0 };
+    char procfd[129];
+    struct stat mystat;
+
+    out[0] = '\0';
+
+    if (fstat(fd, &mystat) == -1) {
